sp_widget.client_script:
api.controller = function($window,$location) {
  var c = this;

  c.filteredQuotas = [];
  c.uiFilter       = { period: '', frequency: '', search: '' };

  /* ================= CREATE QUOTA ================= */
  /*
   * CHANGE: Store the current page URL in sessionStorage before navigating
   * to the Quota Builder. The Quota Builder back button reads this value
   * and returns to exactly this page — so the user lands back on
   * Quota Setup, not on the Administration main page.
   */
  c.createQuota = function() {
    /*
     * Store the current page URL in sessionStorage.
     * The Quota Builder back button reads this and returns here exactly.
     * We append ?returnTo=1 as a marker so the page knows it's a return.
     */
    var currentUrl = $location.absUrl();
    sessionStorage.setItem('qb_origin', currentUrl);

    $location.url('?id=quota_builder');
  };

	c.goBack = function() {
			$location.url('?id=incentnow_admin');
	};

  /* ================= VIEW ASSIGNMENTS ================= */
  /* No change — exact provided code */
  c.viewAssign = function() {
    $location.url('?id=quota_assignments');
  };

  /* ================= QUOTA SUMMARY ================= */
  c.getQuotaSummary = function() {
		var total = 0;
		var totalValue = 0;
		if (c.data.quotaAssignments) {
			c.data.quotaAssignments.forEach(function(q) {
				if ((q.status || '').toLowerCase() === 'active') {  // ✅ FILTER
					total++;
					totalValue += parseFloat(q.targetValue) || 0;
				}
			});
		}
		return {
			total: total,
			totalValue: totalValue
		};
	};

  /* ================= UI FILTER ================= */
  c.applyUIFilter = function() {
    var list = angular.copy(c.data.quotaAssignments || []);

    if (c.uiFilter.period) {
      list = list.filter(function(q) {
        return q.periodName === c.uiFilter.period;
      });
    }

    if (c.uiFilter.frequency) {
      list = list.filter(function(q) {
        return q.distributionMethod === c.uiFilter.frequency;
      });
    }

    if (c.uiFilter.search) {
      var s = c.uiFilter.search.toLowerCase();
      list = list.filter(function(q) {
        return q.name && q.name.toLowerCase().indexOf(s) !== -1;
      });
    }

    c.filteredQuotas = list;
  };

  /* ================= SET TAB ================= */
  c.setTab = function(tab) {
    c.data.activeTab = tab;

    if (tab === 'lookups') {
      c.server.get({ action: 'load_lookups' }).then(function(response) {
        c.data.lookupTables = (response.data && response.data.lookupTables) || [];
      });
      return;
    }

    if (tab === 'settings') {
      return;
    }

    c.server.update({
      action:    'refresh_all',
      period:    c.selectedQuotaPeriod,
      unit:      c.selectedQuotaUnit,
      activeTab: tab
    }).then(function(response) {
      c.data.quotaAssignments = response.data.quotaAssignments;
      c.data.quotaSummary     = response.data.quotaSummary;
      c.filteredQuotas        = angular.copy(c.data.quotaAssignments || []);
    });
  };

  /* ================= INIT ================= */
  c.$onInit = function() {
    c.filteredQuotas = c.data.quotaAssignments || [];

    c.server.update({ action: 'refresh_all' }).then(function(response) {
      c.data.quotaAssignments = response.data.quotaAssignments;
      c.data.quotaSummary     = response.data.quotaSummary;
      c.filteredQuotas        = angular.copy(c.data.quotaAssignments || []);
    });
  };

};

