sp_widget.script:
(function() {

  data.isEdit    = !!options.quota_batch_id;
  data.quotaModel = {};
	data.tableWidget=$sp.getWidget('incentnow-table-widget',{ table: 'x_ctans_incentnow_quota',view:'portal_view',viewperiod:'false'});

	data.isIncentNowGroupAdmin= gs.hasRole('x_ctans_incentnow.business_group_admin') || gs.hasRole('x_ctans_incentnow.admin');


  /* ================= FISCAL CALENDAR ================= */

  data.fiscalPeriods = [];

  var periodGR = new GlideRecordSecure('x_ctans_incentnow_fiscal_calendar');
  periodGR.orderByDesc('fiscal_year_name');
  periodGR.setLimit(12);
  periodGR.query();

  while (periodGR.next()) {
    data.fiscalPeriods.push({
      id:        periodGR.getUniqueValue(),
      name:      periodGR.getValue('fiscal_year_name'),
      startDate: '',
      endDate:   ''
    });
  }

  /* ================= BUSINESS UNITS ================= */

  data.businessUnits = [];

  var buGR = new GlideRecordSecure('business_unit');
  buGR.orderBy('name');
  buGR.query();

  while (buGR.next()) {
    data.businessUnits.push({
      id:   buGR.getUniqueValue(),
      name: buGR.getValue('name')
    });
  }

  /* ================= USERS ================= */

  data.availableUsers = [];

	var userGR = new GlideRecordSecure('x_ctans_incentnow_user_profile');
	userGR.orderBy('user.name');
	userGR.query();

	while (userGR.next()) {
			data.availableUsers.push({
					id: userGR.getValue('user'),
					name: userGR.getDisplayValue('user') || '',
					email: userGR.user.email ? userGR.user.email.toString() : ''
			});
	}

  /* ================= CHECK EXISTING ================= */

 if (input && input.action === 'check_existing') {

    var countGR = new GlideAggregate('x_ctans_incentnow_user_quota_assignment');
    countGR.addQuery('quota.financial_year', input.period_id);
    countGR.addAggregate('COUNT');
    countGR.query();

    if (countGR.next()) {
        data.count = parseInt(countGR.getAggregate('COUNT'), 10);
    }
}

  /* ================= GET USER INFO ================= */

  if (input && input.action === 'get_user_info') {
    var uGR = new GlideRecordSecure('');
    if (uGR.get(input.user_id)) {
      var businessUnit   = '';
      var businessUnitId = '';
      if (uGR.getValue('business_unit')) {
        var bu = new GlideRecordSecure('business_unit');
        if (bu.get(uGR.getValue('business_unit'))) {
          businessUnit   = bu.getValue('name');
          businessUnitId = bu.getUniqueValue();
        }
      }
      data.userInfo = {
        name:           uGR.getValue('name'),
        email:          uGR.getValue('email'),
        businessUnit:   businessUnit,
        businessUnitId: businessUnitId
      };
    }
  }

  /* ================= GET BU USERS ================= */

  if (input && input.action === 'get_bu_users') {
    data.users = [];
    var buUserGR = new GlideRecordSecure('x_ctans_incentnow_user_profile');
    buUserGR.addQuery('business_unit', input.bu_id);
    buUserGR.query();

    while (buUserGR.next()) {
      var buName = '';
      if (buUserGR.getValue('business_unit')) {
        var b = new GlideRecordSecure('business_unit');
        if (b.get(buUserGR.getValue('business_unit'))) {
          buName = b.getValue('name');
        }
      }
      data.users.push({
        id:           buUserGR.getValue('user'),
        name:         buUserGR.user.name.toString(),
        email:        buUserGR.user.email.toString(),
        businessUnit: buName
      });
    }
  }

  /* ================= SAVE QUOTAS ================= */

  if (input && input.action === 'saveQuota') {
    var q       = input.quotaData;
    var quotaGR = new GlideRecordSecure('x_ctans_incentnow_quota');

    if (quotaGR.get(data.sys_id)) {

    } else {
      quotaGR.initialize();
    }

    quotaGR.name            = q.name;
    quotaGR.description     = q.notes;
    quotaGR.fiscal_year     = q.fiscalPeriodId;
    quotaGR.quota_frequency = q.frequency;
    quotaGR.quota_metric    = q.valueType;
    quotaGR.target_value    = q.quotaValue;

    var sysId = quotaGR.update() || quotaGR.insert();

    return {
      status: "success",
      sys_id: sysId
    };
  }

  /* ================= LOAD QUOTA ASSIGNMENTS ================= */

	data.activeQuotaCount = 0;

	var activeGR = new GlideAggregate('x_ctans_incentnow_quota');
	activeGR.addQuery('status', 'active');
	activeGR.addAggregate('COUNT');
	activeGR.query();

	if (activeGR.next()) {
			data.activeQuotaCount = parseInt(activeGR.getAggregate('COUNT'), 10);
	}

  data.quotaAssignments = [];

  var quotaGR2 = new GlideRecordSecure('x_ctans_incentnow_quota');
  quotaGR2.orderByDesc('sys_created_on');
  quotaGR2.query();

  while (quotaGR2.next()) {
    var rawQ    = quotaGR2.getValue('target_value');
    var targetQ = (!rawQ || isNaN(parseFloat(rawQ))) ? 0 : parseFloat(rawQ);

    data.quotaAssignments.push({
      id:                 quotaGR2.getUniqueValue(),
      name:               quotaGR2.getValue('name') || '',
			status: quotaGR2.getValue('status') || '',
      periodName:         quotaGR2.getDisplayValue('fiscal_year') || '',
      targetValue:        targetQ,
      targetDisplay:      targetQ.toString(),
      quotaMetric:        quotaGR2.getDisplayValue('quota_metric') || '',
      distributionMethod: quotaGR2.getDisplayValue('quota_frequency') || ''
    });
  }



})();
